"""Visual hub for the shared Balkan.works platform layers."""


def render_hub_page() -> str:
    return '''<!doctype html><html lang="sr"><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Super App Hub · Balkan.works</title><style>:root{--ink:#092c26;--pine:#0d4036;--paper:#f7f8f4;--orange:#ff6c37;--line:#d9e3dc;--muted:#62746e;--mint:#e5f5eb}*{box-sizing:border-box}body{margin:0;background:var(--paper);font-family:Inter,system-ui;color:var(--ink)}.wrap{max-width:1120px;margin:auto;padding:0 22px}.nav{height:76px;display:flex;justify-content:space-between;align-items:center;border-bottom:1px solid var(--line)}.brand{font-size:24px;font-weight:900;text-decoration:none;color:var(--ink)}.brand i{color:var(--orange)}.nav a:last-child{font-weight:800;color:var(--pine);text-decoration:none}.hero{padding:44px 0 24px}.eyebrow{font-size:12px;color:var(--orange);font-weight:900;letter-spacing:1.3px;text-transform:uppercase}h1{font:clamp(39px,6vw,61px)/.98 Georgia,serif;letter-spacing:-2px;margin:12px 0}.lead{font-size:17px;color:var(--muted);line-height:1.5}.grid{display:grid;grid-template-columns:repeat(4,1fr);gap:12px}.card{background:#fff;border:1px solid var(--line);border-radius:14px;padding:18px}.card b{font-size:29px;display:block}.card span{font-size:12px;color:var(--muted)}.rows{display:grid;grid-template-columns:1fr 1fr;gap:14px;padding:16px 0 40px}.panel{background:#fff;border:1px solid var(--line);border-radius:14px;padding:19px}.panel h2{font:25px Georgia,serif;margin:0}.panel p{font-size:13px;color:var(--muted)}.item{border-top:1px solid var(--line);padding:12px 0}.item b{display:block}.meta{font-size:12px;color:var(--muted)}.locked{max-width:500px;margin:14vh auto;background:#fff;border:1px solid var(--line);border-radius:18px;padding:30px}@media(max-width:700px){.grid{grid-template-columns:1fr 1fr}.rows{grid-template-columns:1fr}}</style><section id="locked" class="locked"><div class="eyebrow">Balkan ID</div><h1>Prijavi se za svoj Hub.</h1><p>Jedan siguran nalog povezuje profil, trust, novčanik, nagrade i lokalne preporuke.</p><a href="/account">Prijava →</a></section><main id="app" hidden class="wrap"><nav class="nav"><a href="/" class="brand">balkan<i>.</i>works</a><a href="/dashboard">Moj Balkan →</a></nav><header class="hero"><div class="eyebrow">Super App Hub</div><h1 id="name">Tvoj Balkan.works.</h1><p class="lead">Zajednički platformski sloj za svaki modul koji koristiš.</p></header><section class="grid"><div class="card"><b id="trust">—</b><span>Trust score</span></div><div class="card"><b id="points">—</b><span>Balkan Rewards poeni</span></div><div class="card"><b id="wallet">—</b><span>Wallet balans</span></div><div class="card"><b id="activity">—</b><span>lokalnih aktivnosti</span></div></section><section class="rows"><article class="panel"><h2>Balkan ID i Trust</h2><p>Jedan identitet za celo tržište — proveren profil, firma i reputacija.</p><div id="badges"></div></article><article class="panel"><h2>Za tebe u blizini</h2><p>Preporuke iz Market modula prema tvojoj regionalnoj lokaciji.</p><div id="recommendations"></div></article><article class="panel"><h2>Wallet i Rewards</h2><p id="reward-note"></p><a href="/dashboard">Pogledaj aktivnosti →</a></article><article class="panel"><h2>Platformska mreža</h2><p>Deals, Save Food, Market i Business koriste isti Balkan ID i centralni API.</p><a href="/search">Pretraži ekosistem →</a></article></section></main><script>const token=()=>localStorage.getItem('balkan_access_token');const esc=s=>String(s??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));async function load(){if(!token())return;try{const h={authorization:'Bearer '+token()},[hub,me]=await Promise.all([fetch('/api/super-app/hub',{headers:h}).then(r=>r.json()),fetch('/api/me',{headers:h}).then(r=>r.json())]);if(hub.detail)throw Error(hub.detail);document.querySelector('#locked').hidden=true;document.querySelector('#app').hidden=false;document.querySelector('#name').textContent='Zdravo, '+me.profile.display_name+'.';document.querySelector('#trust').textContent=hub.trust.score+'/100';document.querySelector('#points').textContent=hub.rewards.points;document.querySelector('#wallet').textContent=Number(hub.wallet.balance||0).toLocaleString('sr-RS',{style:'currency',currency:hub.wallet.currency||'EUR'});document.querySelector('#activity').textContent=hub.activity.favorites+hub.activity.food_reservations;document.querySelector('#badges').innerHTML=hub.trust.badges.length?hub.trust.badges.map(x=>'<div class="item"><b>✓ '+esc(x)+'</b></div>').join(''):'<div class="item">Dopuni profil i verifikacije za viši trust score.</div>';document.querySelector('#recommendations').innerHTML=hub.recommendations.length?hub.recommendations.map(x=>'<div class="item"><b>'+esc(x.title)+'</b><span class="meta">'+esc(x.city_name||x.country_code)+' · '+esc(x.listing_type)+'</span></div>').join(''):'<div class="item">Podesi lokaciju i prati ponude da dobiješ preporuke.</div>';document.querySelector('#reward-note').textContent=hub.rewards.note}catch(_){localStorage.removeItem('balkan_access_token')}}load();</script></html>'''
